import { useState, useEffect } from 'react';
import { Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import { FiHome, FiUsers, FiFileText, FiMessageSquare, FiLink, FiSettings, FiLogOut } from 'react-icons/fi';
import { useAuthStore } from '../store/authStore';
import api from '../services/api';
import toast from 'react-hot-toast';

function AdminLayout({ children }) {
  const location = useLocation();
  const { logout, user } = useAuthStore();

  const menuItems = [
    { path: '/admin', icon: FiHome, label: '仪表盘' },
    { path: '/admin/users', icon: FiUsers, label: '用户管理' },
    { path: '/admin/posts', icon: FiFileText, label: '文章管理' },
    { path: '/admin/comments', icon: FiMessageSquare, label: '评论管理' },
    { path: '/admin/friend-links', icon: FiLink, label: '友链管理' },
  ];

  if (!user) {
    return <Navigate to="/admin/login" />;
  }

  if (user?.role !== 'admin') {
    return <Navigate to="/admin/login" />;
  }

  return (
    <div className="min-h-screen bg-gray-50 flex">
      <aside className="w-64 bg-white border-r border-gray-200 fixed h-full">
        <div className="p-6">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-planet-purple to-planet-pink flex items-center justify-center">
              <span className="text-white font-bold">菜</span>
            </div>
            <span className="font-bold text-xl">后台管理</span>
          </div>
        </div>

        <nav className="px-4 pb-4">
          {menuItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center space-x-3 px-4 py-3 rounded-xl mb-1 transition-colors ${
                location.pathname === item.path
                  ? 'bg-planet-purple/10 text-planet-purple'
                  : 'text-gray-600 hover:bg-gray-50'
              }`}
            >
              <item.icon size={20} />
              <span className="font-medium">{item.label}</span>
            </Link>
          ))}
        </nav>

        <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-gray-200">
          <button
            onClick={logout}
            className="flex items-center space-x-3 px-4 py-3 w-full text-red-600 hover:bg-red-50 rounded-xl transition-colors"
          >
            <FiLogOut size={20} />
            <span className="font-medium">退出登录</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 ml-64">
        <header className="bg-white border-b border-gray-200 px-8 py-4">
          <div className="flex items-center justify-between">
            <h1 className="text-xl font-bold text-gray-900">菜菜星球管理后台</h1>
            <div className="flex items-center space-x-4">
              <span className="text-gray-600">{user?.nickname || user?.username}</span>
              <img
                src={user?.avatar || '/uploads/avatars/default.png'}
                alt={user?.nickname || user?.username}
                className="w-10 h-10 rounded-full object-cover"
              />
            </div>
          </div>
        </header>

        <div className="p-8">
          {children}
        </div>
      </main>
    </div>
  );
}

function DashboardHome() {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const response = await api.get('/admin/dashboard');
      setStats(response.data);
    } catch (error) {
      console.error('获取统计数据失败:', error);
    }
  };

  if (!stats) {
    return (
      <div className="flex justify-center py-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-planet-purple" />
      </div>
    );
  }

  return (
    <div>
      <h2 className="text-2xl font-bold text-gray-900 mb-6">仪表盘</h2>
      
      <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {[
          { label: '总用户数', value: stats.stats.userCount, icon: FiUsers, color: 'blue' },
          { label: '文章数量', value: stats.stats.postCount, icon: FiFileText, color: 'green' },
          { label: '评论数量', value: stats.stats.commentCount, icon: FiMessageSquare, color: 'yellow' },
          { label: '待审核友链', value: stats.stats.pendingFriendLinks, icon: FiLink, color: 'red' },
        ].map((stat, index) => (
          <div key={index} className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm">{stat.label}</p>
                <p className="text-3xl font-bold text-gray-900 mt-1">{stat.value}</p>
              </div>
              <div className={`w-12 h-12 rounded-xl bg-${stat.color}-100 flex items-center justify-center`}>
                <stat.icon className={`text-${stat.color}-600`} size={24} />
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid lg:grid-cols-2 gap-6">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
          <h3 className="font-bold text-gray-900 mb-4">最近注册用户</h3>
          <div className="space-y-4">
            {stats.recentUsers.map((user) => (
              <div key={user.id} className="flex items-center space-x-3">
                <img
                  src={user.avatar || '/uploads/avatars/default.png'}
                  alt={user.nickname || user.username}
                  className="w-10 h-10 rounded-full object-cover"
                />
                <div className="flex-1">
                  <p className="font-medium text-gray-900">{user.nickname || user.username}</p>
                  <p className="text-sm text-gray-500">@{user.username}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
          <h3 className="font-bold text-gray-900 mb-4">最近发布文章</h3>
          <div className="space-y-4">
            {stats.recentPosts.map((post) => (
              <div key={post.id} className="flex items-center space-x-3">
                <div className="w-10 h-10 rounded-lg bg-planet-purple/10 flex items-center justify-center">
                  <FiFileText className="text-planet-purple" />
                </div>
                <div className="flex-1">
                  <p className="font-medium text-gray-900 truncate">{post.title}</p>
                  <p className="text-sm text-gray-500">{post.author?.nickname || post.author?.username}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function UserManagement() {
  const [users, setUsers] = useState([]);

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const response = await api.get('/admin/users');
      setUsers(response.data.users);
    } catch (error) {
      console.error('获取用户列表失败:', error);
    }
  };

  const handleStatusChange = async (userId, status) => {
    try {
      await api.put(`/admin/users/${userId}/status`, { status });
      toast.success('状态更新成功');
      fetchUsers();
    } catch (error) {
      toast.error('更新失败');
    }
  };

  return (
    <div>
      <h2 className="text-2xl font-bold text-gray-900 mb-6">用户管理</h2>
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-4 text-left text-sm font-medium text-gray-500">用户</th>
              <th className="px-6 py-4 text-left text-sm font-medium text-gray-500">角色</th>
              <th className="px-6 py-4 text-left text-sm font-medium text-gray-500">状态</th>
              <th className="px-6 py-4 text-left text-sm font-medium text-gray-500">操作</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {users.map((user) => (
              <tr key={user.id}>
                <td className="px-6 py-4">
                  <div className="flex items-center space-x-3">
                    <img
                      src={user.avatar || '/uploads/avatars/default.png'}
                      alt={user.nickname || user.username}
                      className="w-10 h-10 rounded-full object-cover"
                    />
                    <div>
                      <p className="font-medium text-gray-900">{user.nickname || user.username}</p>
                      <p className="text-sm text-gray-500">@{user.username}</p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                    user.role === 'admin' ? 'bg-purple-100 text-purple-700' : 'bg-gray-100 text-gray-700'
                  }`}>
                    {user.role === 'admin' ? '管理员' : '用户'}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                    user.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                  }`}>
                    {user.status === 'active' ? '正常' : '禁用'}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <button
                    onClick={() => handleStatusChange(user.id, user.status === 'active' ? 'banned' : 'active')}
                    className="text-sm text-planet-purple hover:text-planet-pink"
                  >
                    {user.status === 'active' ? '禁用' : '启用'}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default function AdminDashboard() {
  return (
    <AdminLayout>
      <Routes>
        <Route path="/" element={<DashboardHome />} />
        <Route path="/users" element={<UserManagement />} />
        <Route path="/posts" element={<div className="text-gray-500">文章管理功能开发中...</div>} />
        <Route path="/comments" element={<div className="text-gray-500">评论管理功能开发中...</div>} />
        <Route path="/friend-links" element={<div className="text-gray-500">友链管理功能开发中...</div>} />
      </Routes>
    </AdminLayout>
  );
}
